(function () {
    'use strict';

    const SCRIPT_ID = 'th-sms-bubble-stream-renderer-v5';
    const SCRIPT_NAME = '短信气泡流式预览 v5';
    const STYLE_ID = `${SCRIPT_ID}-style`;
    const GLOBAL_KEY = '__thSmsBubbleStreamRendererV5Cleanup';
    const parentWindow = window.parent || window;
    const parentDocument = parentWindow.document;

    let observer = null;
    let auditTimer = null;
    let scheduled = false;
    const pendingMessages = new Set();

    const MARKER_RE = /\[([^\]\s:：]+)短信\s*[:：]\s*([\s\S]*?)\]/g;

    function roleToKind(role) {
        const value = String(role || '').trim().toLowerCase();
        return value === 'user' || value === '你' || value === '我' ? 'user' : 'char';
    }

    function escapeHtml(value) {
        return String(value || '')
            .replaceAll('&', '&amp;')
            .replaceAll('<', '&lt;')
            .replaceAll('>', '&gt;')
            .replaceAll('"', '&quot;')
            .replaceAll("'", '&#39;');
    }

    function stripMarkup(value) {
        const div = parentDocument.createElement('div');
        div.innerHTML = String(value || '');
        return div.textContent || '';
    }

    function cleanupOldRuntime() {
        for (const key of [
            GLOBAL_KEY,
            '__thSmsBubbleStreamRendererV45Cleanup',
            '__thSmsBubbleStreamRendererV44Cleanup',
            '__thSmsBubbleStreamRendererV43Cleanup',
            '__thSmsBubbleStreamRendererV42Cleanup',
        ]) {
            if (typeof parentWindow[key] === 'function') {
                try { parentWindow[key](); } catch (error) { console.warn(`[${SCRIPT_NAME}] 清理旧实例失败`, error); }
            }
        }

        for (const id of [
            'th-sms-bubble-stream-renderer-style',
            'th-sms-bubble-stream-renderer-v2-style',
            'th-sms-bubble-stream-renderer-v3-style',
            'th-sms-bubble-stream-renderer-v4-style',
            'th-sms-bubble-stream-renderer-v4-1-style',
            'th-sms-bubble-stream-renderer-v4-2-style',
            'th-sms-bubble-stream-renderer-v4-3-style',
            'th-sms-bubble-stream-renderer-v4-4-style',
            'th-sms-bubble-stream-renderer-v4-5-style',
            'th-sms-bubble-stream-renderer-v5-style',
        ]) {
            parentDocument.getElementById(id)?.remove();
        }

        for (const host of parentDocument.querySelectorAll('.th-sms-rendered, .th-sms-preview')) {
            host.remove();
        }

        for (const source of parentDocument.querySelectorAll('.mes_text.th-sms-source-hidden')) {
            source.classList.remove('th-sms-source-hidden');
            delete source.dataset.thSmsHtml;
            delete source.dataset.thSmsText;
        }
    }

    function installStyle() {
        parentDocument.getElementById(STYLE_ID)?.remove();
        const style = parentDocument.createElement('style');
        style.id = STYLE_ID;
        style.textContent = `
            .th-sms-preview {
                width: 100%;
                box-sizing: border-box;
                margin: 0 0 0.65em;
            }
            .th-sms-preview:empty {
                display: none;
            }
            .th-sms-preview .th-sms-row {
                display: flex;
                width: 100%;
                margin: 2px 0;
                box-sizing: border-box;
            }
            .th-sms-preview .th-sms-row.th-sms-char { justify-content: flex-start; }
            .th-sms-preview .th-sms-row.th-sms-user { justify-content: flex-end; }
            .th-sms-preview .th-sms-bubble {
                display: inline-block;
                max-width: 70%;
                padding: 10px 14px;
                font: inherit;
                white-space: pre-wrap;
                overflow-wrap: anywhere;
                box-sizing: border-box;
            }
            .th-sms-preview .th-sms-char .th-sms-bubble {
                background: #e5e5ea;
                color: #1c1c1e;
                border-radius: 18px 18px 18px 4px;
                box-shadow: 0 1px 2px rgba(0,0,0,0.08);
            }
            .th-sms-preview .th-sms-user .th-sms-bubble {
                background: #7a9bbf;
                color: #ffffff;
                border-radius: 18px 18px 4px 18px;
                box-shadow: 0 1px 2px rgba(0,0,0,0.1);
            }
        `;
        parentDocument.head.appendChild(style);
    }

    function makeBubbleHtml(role, text) {
        const kind = roleToKind(role);
        return `<div class="th-sms-row th-sms-${kind}"><div class="th-sms-bubble">${escapeHtml(stripMarkup(text).trim())}</div></div>`;
    }

    function renderSmsPreviewFromHtml(html) {
        MARKER_RE.lastIndex = 0;
        let result = '';
        let match = MARKER_RE.exec(html || '');
        while (match) {
            result += makeBubbleHtml(match[1], match[2]);
            match = MARKER_RE.exec(html || '');
        }
        return result;
    }

    function getPreviewHost(mesText) {
        const mes = mesText.closest('.mes');
        const mesBlock = mesText.closest('.mes_block') || mesText.parentElement;
        if (!mes || !mesBlock) {
            return null;
        }

        let host = mes.querySelector(':scope > .mes_block > .th-sms-preview');
        if (!host) {
            host = parentDocument.createElement('div');
            host.className = 'th-sms-preview';
            mesBlock.insertBefore(host, mesText);
        }
        return host;
    }

    function removePreview(mesText) {
        const mes = mesText && mesText.closest ? mesText.closest('.mes') : null;
        mes?.querySelector(':scope > .mes_block > .th-sms-preview')?.remove();
    }

    function renderMessage(mesText) {
        if (!mesText || !mesText.isConnected || mesText.closest('.th-sms-preview')) {
            return;
        }

        const html = mesText.innerHTML || '';
        if (!html.includes('短信')) {
            removePreview(mesText);
            return;
        }

        const previewHtml = renderSmsPreviewFromHtml(html);
        if (!previewHtml) {
            removePreview(mesText);
            return;
        }

        const host = getPreviewHost(mesText);
        if (!host) {
            return;
        }

        if (host.dataset.thSmsHtml !== previewHtml) {
            host.dataset.thSmsHtml = previewHtml;
            host.innerHTML = previewHtml;
        }
    }

    function queueFromNode(node) {
        const element = node && node.nodeType === 1 ? node : node && node.parentElement;
        if (!element || !element.closest || element.closest('.th-sms-preview')) {
            return;
        }

        const mesText = element.closest('#chat .mes_text');
        if (mesText) {
            pendingMessages.add(mesText);
            return;
        }

        if (element.querySelectorAll) {
            for (const found of element.querySelectorAll('.mes_text')) {
                pendingMessages.add(found);
            }
        }
    }

    function flushPending() {
        const messages = [...pendingMessages];
        pendingMessages.clear();
        for (const mesText of messages) {
            renderMessage(mesText);
        }
    }

    function scheduleRender() {
        if (scheduled) {
            return;
        }
        scheduled = true;
        parentWindow.setTimeout(() => {
            scheduled = false;
            flushPending();
        }, 200);
    }

    function auditRecentMessages() {
        const messages = [...parentDocument.querySelectorAll('#chat .mes_text')];
        for (const mesText of messages.slice(-8)) {
            renderMessage(mesText);
        }
    }

    function startObserver() {
        const chat = parentDocument.querySelector('#chat');
        if (!chat) {
            parentWindow.setTimeout(startObserver, 500);
            return;
        }

        observer?.disconnect();
        const MutationObserverCtor = parentWindow.MutationObserver || MutationObserver;
        observer = new MutationObserverCtor((mutations) => {
            for (const mutation of mutations) {
                queueFromNode(mutation.target);
                for (const node of mutation.addedNodes || []) {
                    queueFromNode(node);
                }
            }
            if (pendingMessages.size > 0) {
                scheduleRender();
            }
        });

        observer.observe(chat, { childList: true, characterData: true, subtree: true });
        auditRecentMessages();
        auditTimer = parentWindow.setInterval(auditRecentMessages, 1500);
        console.log(`[${SCRIPT_NAME}] 已启动`);
    }

    function init() {
        cleanupOldRuntime();
        installStyle();
        startObserver();

        parentWindow[GLOBAL_KEY] = () => {
            observer?.disconnect();
            observer = null;
            if (auditTimer) {
                parentWindow.clearInterval(auditTimer);
                auditTimer = null;
            }
            parentDocument.getElementById(STYLE_ID)?.remove();
            for (const host of parentDocument.querySelectorAll('.th-sms-preview')) {
                host.remove();
            }
        };
    }

    init();
})();
